/**
 * @name getString from input stream flows to File construction
 * @description Trace getString() from stream-reading operations to File construction
 * @kind path-problem
 * @problem.severity error
 * @id java/stream-string-to-file
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking

module StreamStringToFileConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // getString() from binary readers reading from input streams
    exists(MethodCall mc |
      mc.getMethod().hasName("getString") and
      mc.getMethod().getDeclaringType().getEnclosingType() = source.asExpr().(MethodCall).getMethod().getDeclaringType() and
      source.asExpr() = mc
    )
    or
    exists(MethodCall mc |
      mc.getMethod().hasName("getString") and
      (
        mc.getMethod().getDeclaringType().hasQualifiedName("net.sf.mpxj.primavera.p3", "P3PRXFileReader") or
        mc.getMethod().getDeclaringType().hasQualifiedName("net.sf.mpxj.primavera.suretrak", "SureTrakSTXFileReader")
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = cie.getAnArgument()
    )
  }
}

module StreamStringToFileFlow = TaintTracking::Global<StreamStringToFileConfig>;
import StreamStringToFileFlow::PathGraph

from StreamStringToFileFlow::PathNode source, StreamStringToFileFlow::PathNode sink
where StreamStringToFileFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "getString() from stream flows to File construction - path traversal risk."
